#include<bits/stdc++.h>
using namespace std;
#define ll long long
ll n,L,c[50005],he[50005],g[50005],f[50005],sta[50005],p1=1,p2=1;
double slope(ll p1,ll p2){
	ll x1=g[p1]+L,y1=f[p1]+g[p1]*g[p1]+2*g[p1]*L,
	   x2=g[p2]+L,y2=f[p2]+g[p2]*g[p2]+2*g[p2]*L;
	return 1.0*(y1-y2)/(x1-x2);
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>L;
	L++;
	for(int i=1;i<=n;i++){
		cin>>c[i];
		he[i]=he[i-1]+c[i];
		g[i]=he[i]+i;
	}
	sta[p2++]=0;
	for(int i=1;i<=n;i++){
		while(p1<p2-1&&slope(sta[p1+1],sta[p1])<2.0*g[i])p1++;
		int j=sta[p1];
		f[i]=f[j]+(g[i]-g[j]-L)*(g[i]-g[j]-L);
		while(p2>p1+1&&slope(i,sta[p2-1])<slope(i,sta[p2-2]))p2--;
		sta[p2++]=i;
		//cout<<"ans :: "<<j<<endl;
	}
	cout<<f[n];
	return 0;
}

#include<bits/stdc++.h>
using namespace std;
#define ll long long
struct A{
	ll w,l;
	bool jl;
	friend bool operator<(A B,A C){
		if(B.jl!=C.jl)return B.jl<C.jl;
		if(B.w==C.w)return B.l<C.l;
		return B.w<C.w;
	}
}a[50005];
ll f[50005];
double slope(ll p1,ll p2){//a[p1].l<a[p2].l
	ll x1=a[p1].l,y1=f[p1-1],
	   x2=a[p2].l,y2=f[p2-1];
	return 1.0*(y2-y1)/(x2-x1);
}
ll n,sta[50005],p1=1,p2=1;
int main(){
	ios::sync_with_stdio(false);
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i].w>>a[i].l;
	}
	sort(a+1,a+1+n);
	p1=n;
	for(int i=n-1;i;i--){
		if(a[i].l<=a[p1].l&&a[i].w<=a[p1].w)a[i].jl=1;
		else p1=i;
	}
	p1=1;
	sort(a+1,a+1+n);
	while(a[n].jl)n--;
	for(int i=1;i<=n;i++){
		while(p2>p1+1&&slope(i,sta[p2-2])<slope(i,sta[p2-1]))p2--;
		sta[p2++]=i;
		while(p1<p2-1&&-1.0*a[i].w<slope(sta[p1],sta[p1+1]))p1++;
		int j=sta[p1];
		f[i]=a[i].w*a[j].l+f[j-1];
	}
	cout<<f[n];
	return 0;
}

