#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=5e5+5;
ll n,a[N],he[N],he2[N],f[N],b[N];
void add(ll p,ll v){
	for(int i=p;i<=n+1;i+=i&-i){
		b[i]=min(b[i],v);
	}
}
ll cha(ll p){
	ll res=0x7fffffff;
	for(int i=p;i>0;i-=i&-i){
		res=min(res,b[i]);
	}
	return res;
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		he[i]=he[i-1]+a[i];
		he2[i]=he[i];
		b[i]=0x7fffffff;
	}
	if(he[n]<0){
		cout<<-1;
		return 0;
	}
	b[n+1]=0x7fffffff;
	sort(he2+1,he2+1+n+1);
	for(int i=0;i<=n;i++){
		he[i]=lower_bound(he2+1,he2+1+n,he[i])-he2;
	}
	add(he[0],-1);
	for(int i=1;i<=n;i++){
		if(a[i]==0)f[i]=f[i-1];
		else if(he2[he[i]]<0){
			f[i]=0x7fffffff;
			continue;
		}
		else{
			f[i]=i+cha(he[i]);
		}
		add(he[i],f[i]-i-1);
	}
	cout<<f[n];
	return 0;
}

#include<bits/stdc++.h>
using namespace std;
#define ll long long
ll n,m,sum[500002],c[500002],p=1,he;
double b[500002];
struct A{
	ll x,y,v,i,cnt,jian;
	double p;
}a[500002];
bool cmp(A B,A C){
	if(B.y==C.y)return B.x<C.x;
	return B.y<C.y;
}
bool cmp2(A B,A C){
	return B.jian<C.jian;
}
void add(ll p,ll v){
	for(int i=p;i<=n;i+=i&(-i)){
		sum[i]+=v;
	}
}
ll cha(ll p){
	ll res=0;
	for(int i=p;i;i-=i&(-i)){
		res+=sum[i];
	}
	return res;
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		cin>>a[i].x>>a[i].y>>a[i].v;
		a[i].p=a[i].x+1.0*a[i].v*sqrt(2.0*a[i].y/9.8);
		a[i].i=i;
		b[i]=a[i].p;
	}
	for(int i=1;i<=n;i++)cin>>a[i].jian;
	sort(a+1,a+1+n,cmp);
	sort(b+1,b+1+n);
	for(int i=1;i<=n;i++){
		a[i].p=lower_bound(b+1,b+1+n,a[i].p)-b;
	}
	for(int i=1;i<=n;i++){
		//cout<<a[i].x<<' '<<b[(ll)a[i].p]<<' '<<a[i].p<<"    ";
		if(a[i].y!=a[i-1].y){
			for(int l=p;l<i;l++){
				add((ll)a[l].p,-1);
			}
			p=i;
		}
		a[i].cnt=cha(n)-cha(a[i].p-1);
		c[(ll)a[i].p]=a[i].cnt;
		//a[i].jian=min(a[i].jian,a[i].cnt);
	//	he+=a[i].cnt;
		add((ll)a[i].p,1);
		//cout<<he<<' ';
	}
	
	for(int l=p;l<=n;l++){
		add((ll)a[l].p,-1);
	}
	p=n;
//	cout<<'\n';
	for(int i=n;i>=1;i--){
		//cout<<b[(ll)a[i].p]<<' '<<a[i].p<<"    ";
		if(a[i].y!=a[i+1].y){
			for(int l=p;l>i;l--){
				add((ll)a[l].p,-1);
			}
			p=i;
		}
		a[i].cnt+=cha(a[i].p);
		a[i].jian=min(a[i].jian,a[i].cnt);
		he+=a[i].cnt;
		add((ll)a[i].p,1);
		//cout<<he<<' ';
	}
	sort(a+1,a+1+n,cmp2);
	for(int i=n;i>=n-m+1;i--){
		he-=a[i].jian;
	}
	cout<<he;
	return 0;
}

