	//ios::sync_with_stdio(false);
	scanf("%lld%lld",&n,&m);
	for(int i=1;i<=n;i++)scanf("%lf",&a[i]);
	build(1,1,n);
	for(int l=1;l<=m;l++){
		scanf("%lld",&b);
		if(b==1){
			scanf("%lld%lld%lf",&x,&y,&k);
			add(1,x,y,k);
		}
		else if(b==2){
			scanf("%lld%lld",&x,&y);
			double res=CHA(1,x,y)/(y-x+1);
