        a[i].k=(double)a[i].w/a[i].v;
        v[i]=a[i].v;
    }
    sort(v+1,v+1+n);
    int p=unique(v+1,v+1+n)-v;
    for(int i=1;i<=n;i++){
        int p1=lower_bound(v+1,v+p,a[i].v)-v;
        vec[p1].push_back(a[i]);
    }
    m[p-1]=M;
    for(int i=p-2;i>=1;i--){
        m[i]=m[i+1]%v[i+1];
        m[i+1]-=m[i];
    }
    ll ans=0;
    for(int i=1;i<=p-2;i++){
        sort(vec[i].begin(),vec[i].end(),cmp);
        A cnt={0,0};
        for(int l=0;l<vec[i].size();l++){
