                ans+=k.w;
                m[i]-=k.v;
                continue;
            }
            if((cnt+k).v<=v[i+1]){
                cnt+=k;
            }
            else{
                vec[i+1].push_back(cnt);
                cnt=k;
            }
        }
        if(cnt.v!=0)vec[i+1].push_back(cnt);
    }
    sort(vec[p-1].begin(),vec[p-1].end(),cmp);
    for(int i=0;i<vec[p-1].size();i++){
        A k=vec[p-1][i];
        if(m[p-1]-k.v>=0){
            ans+=k.w;
            m[p-1]-=k.v;
        }
        else break;
    }
    cout<<ans;
    return 0;
}

