void add(string s,int v){
	ll k=0;
	for(int i=0;i<s.length();i++){
		if(!trie[k][s[i]-'a'])trie[k][s[i]-'a']=p++;
		k=trie[k][s[i]-'a'];
		cnt[k]+=v;
		if(cnt[k]>t[k].size())t[k].push_back(opt);
	}
}
int cha(string s,int v){
	ll k=0;
	for(int i=0;i<s.length();i++){
		if(!trie[k][s[i]-'a'])return -1;
		k=trie[k][s[i]-'a'];
	}
	if(v<t[k].size())return t[k][v];
	return -1;
}
