void SPFA(int k){
	q.push(k);
	for(int i=1;i<=n;i++){
		dis[i]=0x7fffffff;
	}
	dis[k]=0;
	while(!q.empty()){
		int cur_pos=q.front();
		q.pop();
		in_q[cur_pos]=0;
		if(cnt[cur_pos]>=n){
			jl=1;
			cout<<"-1";
			return;
		}
		for(int i=0;i<v[cur_pos].size();i++){
			int cur_to = v[cur_pos][i].to;
			int cur_cost = v[cur_pos][i].cost;
			if(dis[cur_to]>dis[cur_pos]+cur_cost){
				dis[cur_to]=cur_cost+dis[cur_pos];
				if(!in_q[cur_to]){
					q.push(cur_to);
					in_q[cur_to]=1;
					cnt[cur_to]++;
				}
			}
		}
	}
}
