#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define N 500002
#define eps 0.0000000001
#define delT 0.999
ll n;
double l,a_last,a_best;
struct P{
	double x,y;
}p[102],p_last,p_best;
double energy(P k){
	double res=0x7fffffff;
	for(int i=1;i<=n;i++){
		res=min(res,sqrt((p[i].x-k.x)*(p[i].x-k.x)+(p[i].y-k.y)*(p[i].y-k.y)));
	}
	return -res;
}
P move(P k,double T){
	double dx=2*rand()-RAND_MAX,dy=2*rand()-RAND_MAX;
	return {max((double)0,min(k.x+dx*T,l)),max((double)0,min(l,k.y+dy*T))};
}
void SA(){
	double T=200;
	while(T>=eps){
		P p_cur=move(p_last,T);
		double a_cur=energy(p_cur);
		if(a_cur<a_last){
			a_last=a_cur;
			p_last=p_cur;
		}
		else if(exp((a_last-a_cur)/T)*RAND_MAX>rand()){
			a_last=a_cur;
			p_last=p_cur;
		}
		if(a_cur<a_best){
			a_best=a_cur;
			p_best=p_cur;
		}
		T*=delT;
	}
}
int main(){
	//ios::sync_with_stdio(false);
	cin>>n>>l;
	for(int i=1;i<=n;i++){
		cin>>p[i].x>>p[i].y;
	}
	p_last=p_best={l/2,l/2};
	a_last=a_best=energy({l/2,l/2});
	SA();
	SA();
	SA();
	if(-a_best*n>l)printf("%.3f %.3f",p_best.x,p_best.y);
	else cout<<"GG";
	return 0;
};

