#include <bits/stdc++.h>
using namespace std;
long long n,m,a,b,x,y,z,deep[500002],st[500002][21];
vector<long long>vec[500001];
void down(long long K){
	for(int i=0;i<vec[K].size();i++){
		if(st[vec[K][i]][0]==0){
			deep[vec[K][i]]=deep[K]+1;
			st[vec[K][i]][0]=K;
			down(vec[K][i]);
		}
	}
}
int LCA(long long x,long long y){
	if(deep[x]<deep[y])swap(x,y);
	while(deep[x]>deep[y]){
		x=st[x][min(20,int(log2(deep[x]-deep[y])))];
	}
	if(x==y){
		return x;
	}
	for(int i=20;i>=0;i--){
		if(st[x][i]!=st[y][i]){
			x=st[x][i];
			y=st[y][i];
		}
	}
	return st[x][0];
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>m;
	for(int i=1;i<n;i++){
		cin>>a>>b;
		vec[a].push_back(b);
		vec[b].push_back(a);
	}
	deep[1]=1;
	st[1][0]=1;
	down(1);
	for(int l=1;l<=20;l++){
		for(int i=1;i<=n;++i){
			st[i][l]=st[st[i][l-1]][l-1];
		}
	}
	for(int i=1;i<=m;i++){
		cin>>x>>y>>z;
		if(x==y&&y==z)cout<<x<<' '<<0<<'\n';
		else{
			int c=LCA(x,y),d=LCA(y,z),e=LCA(x,z);
			if(deep[c]==deep[d]){//e xz     2
				cout<<e<<' '<<abs(deep[x]-deep[e])+abs(deep[y]-deep[d])+abs(deep[z]-deep[e])+abs(deep[c]-deep[e])<<'\n';
			}
			else if(deep[c]>deep[d]){//c xy       3
				cout<<c<<' '<<abs(deep[x]-deep[c])+abs(deep[y]-deep[c])+abs(deep[z]-deep[d])+abs(deep[d]-deep[c])<<'\n';
			}
			else{//d yz       1
				cout<<d<<' '<<abs(deep[x]-deep[c])+abs(deep[y]-deep[d])+abs(deep[z]-deep[d])+abs(deep[e]-deep[d])<<'\n';
			}
		}
	}
	return 0;
}

