#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define N 400002
ll n,m,a[N],sum[N],lazy[N],L[N],R[N];
void build(ll K,ll l,ll r){
	L[K]=l;R[K]=r;
	if(l==r){
		sum[K]=a[l];
		return;
	}
	ll mid=(l+r)/2;
	build(K*2,l,mid);
	build(K*2+1,mid+1,r);
	sum[K]=sum[K*2]+sum[K*2+1];
}
void push(ll K){
	lazy[K*2]+=lazy[K];
	lazy[K*2+1]+=lazy[K];
	sum[K*2]+=lazy[K]*(R[K*2]-L[K*2]+1);
	sum[K*2+1]+=lazy[K]*(R[K*2+1]-L[K*2+1]+1);
	lazy[K]=0;
}
void add(ll K,ll l,ll r,ll v){
	if(L[K]>=l&&R[K]<=r){
		sum[K]+=(R[K]-L[K]+1)*v;
		lazy[K]+=v;
		return;
	}
	push(K);
	ll mid=(L[K]+R[K])/2;
	if(l<=mid){
		add(K*2,l,r,v);
	}
	if(r>=mid+1){
		add(K*2+1,l,r,v);
	}
	sum[K]=sum[K*2]+sum[K*2+1];
	return;
}
ll query(ll K,ll l,ll r){
	if(L[K]>=l&&R[K]<=r){
		return sum[K];
	}
	push(K);
	ll mid=(L[K]+R[K])/2,res=0;
	if(l<=mid){
		res+=query(K*2,l,r);
	}
	if(r>=mid+1){
		res+=query(K*2+1,l,r);
	}
