long long n,m,c1,c2,y,val[5002],cnt[5002],vis[5002],jl,o;
struct A{int x,val;};
vector<A>v[5002];
queue<int>q;
void SPFA(){
	q.push(0);
	while(!q.empty()){
		int k=q.front();
		q.pop();
		vis[k]=0;
		if(cnt[k]>=n){
			jl=1;
			cout<<"No";
			return;
		}
		for(int i=0;i<v[k].size();i++){
			if(val[v[k][i].x]>val[k]+v[k][i].val){
				val[v[k][i].x]=v[k][i].val+val[k];
				if(!vis[v[k][i].x]){
					q.push(v[k][i].x);
					vis[v[k][i].x]=1;
					cnt[v[k][i].x]++;
				}
			}
		}
	}
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>m;
	for(int i=1;i<=m;i++){
		cin>>o;
		if(o==1){
			cin>>c1>>c2>>y;
			v[c1].push_back(A{c2,-y});
		}
		else if(o==2){
			cin>>c1>>c2>>y;
			v[c2].push_back(A{c1,y});
		}
		else{
			cin>>c1>>c2;
			v[c2].push_back(A{c1,0});
			v[c1].push_back(A{c2,0});
		}
		
	}
	for(int i=1;i<=n;i++){
		v[0].push_back(A{i,0});
		val[i]=0x7fffffff;
	}
	SPFA();
	if(!jl)cout<<"Yes";
	return 0;
}

