int findfa(int K){
	if(fa[K]==K)return K;
	return fa[K]=findfa(fa[K]);
}
void merge(int X,int Y){fa[findfa(Y)]=findfa(X);}
int CHA(int X,int Y){
	if(findfa(fa[X])==findfa(fa[Y]))return 1;
	return 0;
}
