#define ll long long
const ll MOD=1e9+7;
const int MaxN=3;
ll cnt;
void matrix_vector_product(ll a[MaxN][MaxN],ll b[MaxN],ll n){
   ll temp[MaxN];
   memset(temp, 0, sizeof(temp));
   for(int i = 0; i < n; i++)
       for(int k = 0; k < n; k++)
           temp[i] = (temp[i] + a[i][k] * b[k]) % MOD;
   memcpy(b,temp,sizeof(temp));
}
void matrix_self_product(ll a[MaxN][MaxN],int n){
    ll tmp[MaxN][MaxN];
    memset(tmp,0,sizeof(tmp));
    for(int i=0;i<n;i++)
    for(int j=0;j<n;j++)
    for(int m=0;m<n;m++)                
    tmp[i][j]=(tmp[i][j]+a[i][m]*a[m][j])%MOD;
    memcpy(a,tmp,sizeof(tmp));
}
void matrix_product(ll a[MaxN][MaxN],ll b[MaxN][MaxN],int n){
    ll tmp[MaxN][MaxN];
    memset(tmp,0,sizeof(tmp));
    for(int i=0;i<n;i++)
    for(int j=0;j<n;j++)
    for(int m=0;m<n;m++)                
    tmp[i][j]=(tmp[i][j]+a[i][m]*b[m][j])%MOD;
    memcpy(a,tmp,sizeof(tmp));
}
void matrix_fast_power(ll a[MaxN][MaxN],ll n,ll t){
    ll res[MaxN][MaxN];
    memset(res,0,sizeof(res));
    for(int i=0;i<n;i++)
        res[i][i]=1;
    ll tmp[MaxN][MaxN];
    memcpy(tmp,a,sizeof(tmp));
    for(ll i=t;i;i>>=1){
        if(i%2)matrix_product(res,tmp,n);
        matrix_self_product(tmp,n);
    }
    memcpy(a,res,sizeof(res));
}
int main(){
	ios::sync_with_stdio(false);
    ll a[MaxN][MaxN],b[MaxN],n,m,t;
    cin>>t;
    for(int i=1;i<=t;i++){
    	cin>>n;
	    memset(a,0,sizeof(a));
		a[0][1]=1;
		a[1][2]=1;
		a[2][0]=1;
		a[2][2]=1;
	    matrix_fast_power(a,3,n);
	    b[0]=0;
	    b[1]=1;
	    b[2]=1;
	    matrix_vector_product(a,b,3);
	    cout<<b[0]%MOD<<'\n';
	}
    return 0;
}

