#include<bits/stdc++.h>
using namespace std;
#define ll long long
ll n,m,col[100002],jl,a,b,c,mid,L,R;
struct A{
	ll b,c;
};
vector<A>vec[100002];
void paint(ll k){
	for(int i=0;i<vec[k].size()&&jl==0;i++){
		if(vec[k][i].c<mid)continue;
		if(col[vec[k][i].b]==0){
			col[vec[k][i].b]=3-col[k];
			paint(vec[k][i].b);
		}
		else if(col[vec[k][i].b]==col[k]){
			jl=1;
			return;
		}
	}
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>m;
	for(int i=1;i<=m;i++){
		cin>>a>>b>>c;
		vec[a].push_back({b,c});
		vec[b].push_back({a,c});
	}
	L=0,R=1e9;
	while(L<R-1){
		mid=(L+R)/2;
		for(int i=1;i<=n;i++)col[i]=0;
		jl=0;
		for(int i=1;i<=n&&jl==0;i++){
			if(col[i]==0){
				col[i]=1;
				paint(i);
			}
		}
		if(jl==1)L=mid;
		else R=mid;
	}
	cout<<R-1;
	return 0;
}

