#include<bits/stdc++.h>
using namespace std;
#define ll long long
ll n,m,a[100005],sum[400005],L[400005],R[400005],lazyk[400005],lazyd[400005];
void build(ll k,ll l,ll r){
	L[k]=l;R[k]=r;
	if(l==r){
		sum[k]=a[l];
		return;
	}
	ll mid=(l+r)/2;
	build(k*2,l,mid);
	build(k*2+1,mid+1,r);
	sum[k]=sum[k*2]+sum[k*2+1];
}
void update(ll k){
	ll x=lazyk[k],y=lazyk[k]+lazyd[k]*(R[k*2]-L[k]);
	sum[k*2]+=x*(R[k*2]-L[k*2]+1)+(y+lazyd[k])*(R[k*2]-L[k*2])/2;
	lazyk[k*2]+=x;

	x=y+lazyd[k];y=lazyk[k]+lazyd[k]*(R[k]-L[k]);
	sum[k*2+1]+=x*(R[k*2+1]-L[k*2+1]+1)+y*(R[k*2+1]-L[k*2+1])/2;
	lazyk[k*2+1]+=x;

	lazyd[k*2]+=lazyd[k];
	lazyd[k*2+1]+=lazyd[k];

	lazyk[k]=0;
	lazyd[k]=0;
}
void add(ll k,ll l,ll r,ll K,ll D){
	if(L[k]>=l&&R[k]<=r){
		ll x=K+D*(L[k]-l),y=k+D*(R[k]-l);//首项 末项 
		sum[k]+=x*(R[k]-L[k]+1)+(y-x+D)*(R[k]-L[k])/2;
		lazyk[k]+=x;
		lazyd[k]+=D;
		return;
	}
	update(k);
	ll mid=(L[k]+R[k])/2;
	if(l<=mid)add(k*2,l,r,K,D);
	if(r>=mid+1)add(k*2+1,l,r,K,D);
	sum[k]=sum[k*2]+sum[k*2+1];
}
ll cha(ll k,ll p){
	if(L[k]==R[k]){
		return sum[k];
	}
	update(k);
	ll mid=(L[k]+R[k])/2;
	if(p<=mid)return cha(k*2,p);
	else return cha(k*2+1,p);
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	build(1,1,n);
	for(int i=1;i<=m;i++){
		ll o;
		cin>>o;
		if(o==1){
			ll l,r,K,D;
			cin>>l>>r>>K>>D;
