char y;
void build(long long K,long long l,long long r){
	L[K]=l;
	R[K]=r;
	if(l==r){
		sum[K]=a[r];
		return;
	}
	long long mid=(r-l)/2+l;
	build(K*2,l,mid);
	build(K*2+1,mid+1,r);
	sum[K]=max(sum[K*2],sum[K*2+1]);
}
long long cha(long long K,long long l,long long r){
	if(l<=L[K]&&R[K]<=r)return sum[K];
	long long mid=(R[K]-L[K])/2+L[K],res=-0x7ffffffffffffff;
	if(l<=mid)res=max(res,cha(K*2,l,r));
	if(r>mid)res=max(res,cha(K*2+1,l,r));
	return res;
}
void add(long long K,long long x,long long val){
	if(L[K]==R[K]){
		sum[K]=val;
		return;
	}
	long long mid=(R[K]-L[K])/2+L[K];
	if(x<=mid)add(K*2,x,val);
	else add(K*2+1,x,val);
	sum[K]=max(sum[K*2],sum[K*2+1]);
}
