typedef long double ll;
const int N=1e5+10;
int n,m;

int head[N],to[N*10],nxt[N*10],cnt;
int in[N],out[N];
vector<int> ans;


void add_edge(int u,int v)
{
    to[cnt]=v;
    nxt[cnt]=head[u];
    head[u]=cnt++;
}

struct Fraction
{
    ll p;
    unsigned long long c2,c3,c5;
    Fraction operator +(const Fraction &rhs) const
    {
        Fraction res;
        res.p=0;
        res.c2=max(rhs.c2,res.c2);
		res.c3=max(rhs.c3,res.c3);
		res.c5=max(rhs.c5,res.c5);
		ll t=rhs.p*pow(2,res.c2-rhs.c2)*pow(3,res.c3-rhs.c3)*pow(5,res.c5-rhs.c5);
		t+=p*pow(2,res.c2-rhs.c2)*pow(3,res.c3-rhs.c3)*pow(5,res.c5-rhs.c5);
		while(round(t/2)*2==t&&res.c2>0){
			res.c2--;
			t/=2;
		}
		while(round(t/3)*3==t&&res.c3>0){
			res.c3--;
			t/=3;
		}
		while(round(t/5)*5==t&&res.c5>0){
			res.c5--;
			t/=5;
		}
		res.p=t;
        return res;
    }
}fra[N];


void top_sort()
{
    queue<int> q;
    for(int i=1;i<=n;i++)
        if(in[i]==0) q.push(i),fra[i].p=1;
    while(!q.empty())
    {
        int u=q.front();
        q.pop();
        if(out[u]==2) fra[u].c2+=1;
        if(out[u]==3) fra[u].c3+=1;
        if(out[u]==4) fra[u].c2+=2;
        if(out[u]==5) fra[u].c5+=1;
        for(int i=head[u];i!=-1;i=nxt[i])
        {
            int v=to[i];
            fra[v]=fra[v]+fra[u];
            if(--in[v]==0) q.push(v);
        }
    }
}


int main()
{
    cin>>n>>m;
    memset(head,-1,sizeof head);
    for(int i=1;i<=n;i++)
    {
        cin>>out[i];
        if(out[i]==0) ans.push_back(i);
        for(int x,j=1;j<=out[i];j++)
        {
            cin>>x;
            in[x]++;
            add_edge(i,x);
        }
    }

    top_sort();

    for(int i=0;i<ans.size();i++)
    {
        printf("%.0Lf",fra[ans[i]].p);
        putchar(' ');
        ll q=pow(2,fra[ans[i]].c2);
        q*=pow(3,fra[ans[i]].c3);
        q*=pow(5,fra[ans[i]].c5);
        printf("%.0Lf",q);
        putchar('\n');
    }

    return 0;
}

