#define ll long long
ll n,m,s,stp[500002],fa[500002][22];
vector<ll>v[500002];
void dfs(ll k,ll f){
	for(int i=0;i<v[k].size();i++){
		if(v[k][i]!=f){
			stp[v[k][i]]=stp[k]+1;
			fa[v[k][i]][0]=k;
			dfs(v[k][i],k);
		}
	}
}
ll cha(ll p1,ll p2){
	if(stp[p1]<stp[p2])swap(p1,p2);
	for(int i=20;i>=0;i--){
		if(stp[fa[p1][i]]>=stp[p2]){
			p1=fa[p1][i];
		}
	}
	if(p1==p2)return p1;
	for(int i=20;i>=0;i--){
		if(fa[p1][i]!=fa[p2][i]){
			p1=fa[p1][i];
			p2=fa[p2][i];
		}
	}
	return fa[p1][0];
}
