#include <bits/stdc++.h>
using namespace std;
long long a,b,c,d[1000002],f=1,mi;
void add(int x) {
	d[f] = x;
	c = f;
	while(c>1){
		if(d[c]<d[c/2]){
			swap(d[c],d[c/2]);
		}
		else break;
		c/=2;
	}
	f++;
}
void del() {
	d[1]=d[f-1];
	f--;
	c=1;
	while(c<=(f-1)/2){
		if(c*2<=f-1&&d[c*2]<d[c*2+1]){
			if(d[c]>d[c*2]){
				swap(d[c],d[c*2]);
				c*=2;
				}
				else break;
			}
		else{
			if(d[c]>d[c*2+1]){
				swap(d[c],d[c*2+1]);
				c=c*2+1;
			}
			else break;
		}
	}
}
int top() {
	return d[1];
}
int main(){
	ios::sync_with_stdio(false);
	cin>>a;
	for(int i=1;i<=a;i++){
		cin>>b;
		if(b==1){
			int x;
			cin>>x;
			add(x);
		}
		else if(b==2)cout<<top()<<endl;
		else{
			del();
		}
	}
	return 0;
}

