void add(int x) {
	c[e] = x;
	d = e;
	while(d>1){
		if(c[d]<c[d/2]){
			swap(c[d],c[d/2]);
		}
		else break;
		d/=2;
	}
	e++;
}
void del(){
	c[1]=c[e-1];
	e--;
	d=1;
	while(d<=(e-1)/2){
		if(d*2<=e-1&&c[d*2]<c[d*2+1]){
