int CHA(int K){
	if(f[K]==K)return K;
	return f[K]=CHA(f[K]);
}
int main(){
	ios::sync_with_stdio(false);
	while(1){
		cin>>n;
		if(n==0)return 0;
		cin>>m;
		for(int i=1;i<=n;i++)f[i]=i;
		while(!lu.empty())lu.pop();
		cnt=0;
		for(int i=1;i<=m;i++){
			cin>>p.x>>p.y;
			p.val=1;
			lu.push(p);
			swap(p.x,p.y);
			lu.push(p);
		}
		while(!lu.empty()){
			p=lu.top();
			lu.pop();
			if(CHA(p.x)!=CHA(p.y)){
				f[CHA(p.x)]=f[p.y];
				cnt++;
				if(cnt==n-1){
					break;
				}
			}
		}
		cout<<n-1-cnt<<'\n';
	}
