#include <bits/stdc++.h>
using namespace std;
//变量创建在外面，全局变量 
int M,N,B[100][100],cnt=1;
string a;
int A[100][100];  //注意是【字符】二维数组 
void DFS(int x,int y){ //代表从x行y列进行DFS
	//三个剪枝条件 
	if(A[x][y]=='0') return; //如果此处是X,就没必要继续判断连通 
	else if(x<0||x>=M||y<0||y>=N) return; //如果x,y出界了 也不必继续了
	else if(B[x][y]!=0) return; //如果编号不为0,进行过编号了,也不必继续 防止死循环
	else{
		B[x][y]=cnt; //给到编号 
		DFS(x-1,y); //上 
		DFS(x+1,y); //下 
		DFS(x,y-1); //左 
		DFS(x,y+1); //右 
	} 	
} 
int main(){
	//二维数组的输入 
	cin>>M>>N;
	for (int i=0;i<M;i++){
		cin>>a;
		for (int j=0;j<N;j++){
			A[i][j]=a[j];  //i表示行,j表示列 
		}
	}
	//每个点都遍历 
	for (int i=0;i<M;i++){
		for (int j=0;j<N;j++){
			if(A[i][j]!='0'&&B[i][j]==0){
				//如果i行j列这个点
				//既是R 又还没编号
				//则可以以它入手，DFS找连通块
				DFS(i,j);
				cnt++; //找完之后cnt变大 下一个连通块是新的编号 
			} 
		}
	}
	//最后输出cnt-1 
	cout<<cnt-1<<endl; 
}

