long long n,m,a[102][102],
dx[9]={1,-1,0,0,-1,1,1,-1},
dy[9]={0,0,-1,1,-1,1,-1,1};
char ch;
int main(){
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		for(int l=1;l<=m;l++){
			cin>>ch;
			if(ch=='*'){
				a[i][l]=-1;
				for(int j=0;j<8;j++){
					if(a[i+dx[j]][l+dy[j]]!=-1)a[i+dx[j]][l+dy[j]]++;
				}
			}
		}
	}
	for(int i=1;i<=n;i++){
		for(int l=1;l<=m;l++){
			if(a[i][l]==-1)cout<<'*';
			else cout<<a[i][l];
		}
		cout<<'\n';
	}
	return 0;
}

