#define ull unsigned long long
const int N=1e5+5;
ll n,m,k;
vector<int>vec[N];
struct A{
	int fh;ull x;
}a[N];

int f[N],bigson[N],siz[N],top[N],dfn[N],p=1,dep[N],pdfn[N];//pdfn[原点]:原点在dfn的下标 
void dfs(int k){
	siz[k]=1;
	bigson[k]=-1;
	for(int i=0;i<vec[k].size();i++){
		int to=vec[k][i];
		if(to==f[k])continue; 
		dep[to]=dep[k]+1;
		f[to]=k;
		dfs(to);
		siz[k]+=siz[to];
		if(bigson[k]==-1||siz[to]>siz[vec[k][bigson[k]]])bigson[k]=i;
	}
}
void dfs2(int k){
	dfn[p++]=k;
	pdfn[k]=p-1;
	if(vec[k].size()>1){
		top[vec[k][bigson[k]]]=top[k];
		dfs2(vec[k][bigson[k]]);
	}
	for(int i=0;i<vec[k].size();i++){
		int to=vec[k][i];
		if(to==f[k]||i==bigson[k])continue;
		top[to]=to;
		dfs2(to);
	}
}
struct B{
	bitset<64>l[2],r[2];
	B operator=(A v){
		l[0]=r[0]=0;
		l[1].set(),r[1].set();
		bitset<64>bs=v.x;
		if(v.fh==1){//&
			l[0]&=bs;
			l[1]&=bs;
			r[0]&=bs;
			r[1]&=bs;
		}
		else if(v.fh==2){//|
			l[0]|=bs;
			l[1]|=bs;
			r[0]|=bs;
			r[1]|=bs;
		}
		else if(v.fh==3){//^
			l[0]^=bs;
			l[1]^=bs;
			r[0]^=bs;
			r[1]^=bs;
		}
		return *this;
	}
	friend B operator+(B C,B D){
		for(int i=0;i<64;i++){
			C.l[0][i]=D.l[C.l[0][i]][i];
			C.l[1][i]=D.l[C.l[1][i]][i];
			D.r[0][i]=C.r[D.r[0][i]][i];
			D.r[1][i]=C.r[D.r[1][i]][i];
		}
		return B{{C.l[0],C.l[1]},{D.r[0],D.r[1]}};
	}
};
B seg[N*4];
int L[N*4],R[N*4];
void build(int k,int l,int r){
	L[k]=l;R[k]=r;
	if(l==r){
		seg[k]=a[dfn[l]];
		return;
	}
	int mid=(l+r)/2;
	build(k*2,l,mid);
	build(k*2+1,mid+1,r);
	seg[k]=seg[k*2]+seg[k*2+1];
}
void chg(int k,int p,A v){
	if(L[k]==R[k]&&L[k]==p){
		seg[k]=v;
		return;
	}
	int mid=(L[k]+R[k])/2;
	if(p<=mid)chg(k*2,p,v);
	else chg(k*2+1,p,v);
	seg[k]=seg[k*2]+seg[k*2+1];
}
B cal(int k,int l,int r){
	if(L[k]>=l&&R[k]<=r){
		return seg[k];
	}
	B res;res=A{0,0};
	int mid=(L[k]+R[k])/2;
	if(l<=mid)res=res+cal(k*2,l,r);
	if(r>=mid+1)res=res+cal(k*2+1,l,r);
	return res;
}
B LCA(int p1,int p2,bool fx){//0: p1->p2 1:p1<-p2
	B res1,res2;
	res1=res2=A{0,0}; 
	while(top[p1]!=top[p2]){
		if(dep[p1]<dep[p2])swap(p1,p2),fx=!fx;
		if(!fx)res1=cal(1,top[p1],p1)+res1;
		else res2=cal(1,top[p1],p1)+res2;
		p1=top[p1];
		if(f[p1]!=p2){
			if(!fx)res1=cal(1,f[p1],f[p1])+res1;//-----
			else res2=cal(1,f[p1],f[p1])+res2;//-----
		}
		p1=f[p1];
	}
	if(p1!=p2){
		if(dep[p1]<dep[p2])swap(p1,p2),fx=!fx;
		if(!fx)res1=cal(1,p2,p1)+res1;
		else res2=cal(1,p2,p1)+res2;
	}
	swap(res1.l,res1.r);
	return res1+res2;
}
