D[100002],f[100002],from[100002],edge[100002],head[100002],Next[1000002],val[1000002],to[1000002],tot=2,maxx,max2,pos,pos2,Y;//pos=position位置 
//D[点号]=该子树的最大深度 f[点号]=经过此点的最长链 from最长链，辅助取反 
//head[点号1]=边号 Next[边号]=上一个边的边号 val[边号]=边权 to[边号]=点号2 
void Add(int A,int B,int V){
	Next[tot]=head[A];
	head[A]=tot;
	to[tot]=B;
	val[tot]=V;
	tot++;
}
void DFS(int X,int fa,int cnt){
	for(int i=head[X];i;i=Next[i]){//i：边的编号 
		Y=to[i];
		if(Y==fa)continue;
		DFS(Y,X,cnt+val[i]);
	}
	if(cnt>maxx){
		maxx=cnt;
		pos=X;
	}
}
void DFS2(int X,int fa,int cnt){
	for(int i=head[X];i;i=Next[i]){//i：边的编号 
		Y=to[i];
		if(Y==fa)continue;
		from[Y]=X;
		edge[Y]=i;
		DFS2(Y,X,cnt+val[i]);
	}
	if(cnt>maxx){
		maxx=cnt;
		pos=X;
	}
}
void MODIFY(int K){//modify模式 
	val[edge[K]]=-val[edge[K]];
	val[edge[K]^1]=-val[edge[K]^1];
	if(K!=pos2&&K)MODIFY(from[K]);
}
void DP(int X,int fa){
	for(int i=head[X];i;i=Next[i]){//i：边的编号 
		Y=to[i];
		if(Y==fa)continue;
		DP(Y,X);
		f[X]=max(f[X],max(0,D[X])+D[Y]+val[i]);
		D[X]=max(D[X],D[Y]+val[i]);
		max2=max(max2,f[X]);
	}
}
