void build(ll k,ll l,ll r){
	L[k]=l;R[k]=r;
	if(l==r){
		sum[k]=a2[l];
		minn[k]=a2[l];
		return;
	}
	ll mid=(l+r)/2;
	build(k*2,l,mid);
	build(k*2+1,mid+1,r);
	sum[k]=sum[k*2]+sum[k*2+1];
	minn[k]=min(minn[k*2],minn[k*2+1]);
}
void push(ll k){
	minn[k*2]+=lazy[k];
	minn[k*2+1]+=lazy[k];
	sum[k*2]+=(R[k*2]-L[k*2]+1)*lazy[k];
	sum[k*2+1]+=(R[k*2+1]-L[k*2+1]+1)*lazy[k];
	lazy[k*2]+=lazy[k];
	lazy[k*2+1]+=lazy[k];
	lazy[k]=0;
}
void add(ll k,ll l,ll r,ll v){
	if(L[k]>=l&&R[k]<=r){
		sum[k]+=(R[k]-L[k]+1)*v;
		lazy[k]+=v;
		minn[k]+=v;
		return;
	}
	push(k);
	ll mid=(L[k]+R[k])/2;
	if(l<=mid){
		add(k*2,l,r,v);
	}
	if(r>=mid+1){
		add(k*2+1,l,r,v);
	}
	sum[k]=sum[k*2]+sum[k*2+1];
	minn[k]=min(minn[k*2],minn[k*2+1]);
}
ll cha(ll k,ll l,ll r){
	if(L[k]>=l&&R[k]<=r){
		return minn[k];
	}
	push(k);
	ll mid=(L[k]+R[k])/2,res=0x7fffffff;
	if(l<=mid){
		res=min(res,cha(k*2,l,r));
	}
	if(r>=mid+1){
		res=min(res,cha(k*2+1,l,r));
	}
	return res;
}
