struct A{
	ll y,x1,x2,v;
}a[200005];
bool cmp(A B,A C){
	if(B.y==C.y)return B.v<C.v;
	return B.y>C.y;
}
void up(ll k){
	if(cnt[k])sum[k]=b[R[k]]-b[L[k]];////
	else{
		if(R[k]-L[k])sum[k]=sum[k*2]+sum[k*2+1];
		else sum[k]=0;
	}
}
void build(ll k,ll l,ll r){
	L[k]=l;R[k]=r;
	if(l==r){
		return;
	}
	ll mid=(l+r)/2;
	build(k*2,l,mid);
	build(k*2+1,mid+1,r);
}
void add(ll k,ll l,ll r,int v){
	if(L[k]>=l&&R[k]<=r){
		cnt[k]+=v;
		up(k);
		return;
	}
	ll mid=(L[k]+R[k])/2;
	if(l<=mid)add(k*2,l,r,v);
	if(r>=mid+1)add(k*2+1,l,r,v);
	up(k);
}
