	ll x,y;
	void huajian(){//化简
		if(x==0){y=1;return;}
		if(y==0){x=1;return;}
		ll gcd=__gcd(x,y);
		x/=gcd;y/=gcd;
	}
	friend xy operator*(xy B,ll C){
		B.x*=C;
		B.huajian();
		return B;
	}
	friend xy operator+(ll B,xy C){
		xy k={B*C.y+C.x,C.y};
		k.huajian();
		return k;
	}
	friend bool operator<(xy B,xy C){
		return B.x*C.y<C.x*B.y;
	} 
}a[25];
