			xy o={k2.y-k1.y,k2.x-k1.x};
			o.huajian();
			ll u=o.x*1000+o.y+1001000;
			ll U=lower_bound(c.begin(),c.begin()+p+1,u)-c.begin();
			if(!vis[i][U]){
				vis[i][U]=1;
