		for(int l=st;l;l=l&(l-1)){//从低到高位删1 
			ll u=__lg(l&-l);//取出最低位1  (这一步停在 u号点) 
			if(f[st][u]==0x7fffffff)continue;//这个点没被 更新/走到 过
			for(int j=((1<<n)-1)&~st;j;j&=j-1){//j -> 未走过哪些点(1未走0走过)
				ll v=__lg(j&-j);//取出最低位1  (下一步走到 v号点) 
				f[st|(1<<v)][v]=min(f[st|(1<<v)][v],f[st][u]+g[u][v]);
			}
		}
	}
