struct ODT{
	map<int,int>mp;
    using it=map<int,int>::iterator;
	int n;
	void init(int ed,int v){
		n=ed;
		mp[1]=v,mp[n+1]=-1;
	}
	void split(int x){//分裂 切割 
		it p=prev(mp.upper_bound(x));
		mp[x]=p->second;
	}
	void perform(int l,int r){
	    r++;
		split(l);split(r);
		it p=mp.find(l),p2=mp.find(r);
		mp.erase(p,p2);
	}
	void assign(int l,int r,int v){//区间推平 
		perform(l,r);
		mp[l]=v;
		it p=mp.find(l);
		if(p!=mp.begin()&&prev(p)->second==p->second)mp.erase(p);
	}
	int qry(int l,int r,int v){
		int res=0;
		split(l);split(r+1);
		it p1=mp.find(l),p2=next(mp.find(l)),ed=mp.find(r+1);
		while(p2!=ed){
            if(p1->second==v)res+=p2->first-p1->first;
            if(p1->second==p2->second){//去重 
                p1=p2;
                p2=mp.erase(p2);
            }
            else p1=p2++; 
        }
	    return res;
	}
	//------------------------
	int fd(int len){
		int p=1,cnt=0;
		it p1=mp.begin(),p2=next(mp.begin()),ed=mp.end();
		while(p2!=ed){
            if(p1->second==0){
            	cnt+=p2->first-p1->first;
            	if(cnt>=len){
                    assign(p,p+len-1,1);
            		return p;
            	}
            }
            else{
            	cnt=0;
            	p=p2->first;
            }
            if(p1->second==p2->second){
                p1=p2;
                p2=mp.erase(p2);
            }
            else{
               p1=p2++; 
            }
        }
	    return 0;
	}
}a;
