,x[300002],y[300002];
struct A{
	ll x,v;
};
vector<A>vec[300002];
void DFS(ll k,ll ceng){
	deep[k]=ceng;
	vis[k]=1;
	for(int i=0;i<vec[k].size();i++){
		if(!vis[vec[k][i].x]){
			st[vec[k][i].x][0]=k;
			v[vec[k][i].x]=vec[k][i].v+v[k];
			DFS(vec[k][i].x,ceng+1);
		}
	}
}
void down(long long K){
	for(int i=0;i<vec[K].size();i++){
		if(st[vec[K][i].x][0]==0){
			deep[vec[K][i].x]=deep[K]+1;
			st[vec[K][i].x][0]=K;
			down(vec[K][i].x);
		}
	}
}
ll LCA(long long x,long long y){
	if(deep[x]<deep[y])swap(x,y);
	while(deep[x]>deep[y]){
		x=st[x][min(20,int(log2(deep[x]-deep[y])))];
	}
	if(x==y)return x;
	for(int i=20;i>=0;i--){
		if(st[x][i]!=st[y][i]){
			x=st[x][i];
			y=st[y][i];
		}
	}
	return st[x][0];
}
ll DFS2(ll k,ll f){
	for(int i=0;i<vec[k].size();i++){
		if(vec[k][i].x!=f){
			d[k]+=DFS2(vec[k][i].x,k);
		}
	}
	return d[k];
}
bool check(ll K){
	memset(d,0,sizeof(d));
	ll cnt=0,p=1;
	for(int i=1;i<=m;i++){
		if(c[i]>K){
			sta[p++]=i;
			cnt++;
			d[x[i]]++;d[y[i]]++;
			ll lca=LCA(x[i],y[i]);
			d[lca]-=2;
		}
	}
	DFS2(1,-1);
	ll jl;
	for(int i=1;i<=n;i++){
		jl=0;
		if(d[i]>=cnt){
			for(int l=1;l<p;l++){
				if(c[l]-(v[l]-v[st[v[l]][0]])<=K)jl++;
			}
		}
		if(jl==cnt)return 1;
	}
	return 0;
}
