#include<bits/stdc++.h>
using namespace std;
#define ll long long
ll n,m,cnt,a[100005],L[400005],R[400005],lazy_paint[400005],lazy_rev[400005],sum[400005];
struct A{
	ll l,mid,r;
}len[400005][2];
void ret(ll k){
	sum[k]=sum[k*2]+sum[k*2+1];
	A b=len[k*2][1],c=len[k*2+1][1];
	len[k][1]={b.l,max(b.r+c.l,max(b.mid,c.mid)),c.r};
	if(b.l==R[k*2]-L[k*2]+1)len[k][1].l+=c.l;
	if(c.r==R[k*2+1]-L[k*2+1]+1)len[k][1].r+=b.r;
	len[k][1].mid=max(len[k][1].mid,len[k][1].l);
	len[k][1].mid=max(len[k][1].mid,len[k][1].r);

	b=len[k*2][0],c=len[k*2+1][0];
	len[k][0]={b.l,max(b.r+c.l,max(b.mid,c.mid)),c.r};
	if(b.l==R[k*2]-L[k*2]+1)len[k][0].l+=c.l;
	if(c.r==R[k*2+1]-L[k*2+1]+1)len[k][0].r+=b.r;
	len[k][0].mid=max(len[k][0].mid,len[k][0].l);
	len[k][0].mid=max(len[k][0].mid,len[k][0].r);
}
void build(ll k,ll l,ll r){
	L[k]=l;R[k]=r;
	lazy_paint[k]=-1;
	if(l==r){
		sum[k]=a[l];
		len[k][1]={a[l],a[l],a[l]};
		len[k][0]={1-a[l],1-a[l],1-a[l]};
		return;
	}
	ll mid=(l+r)/2;
	build(k*2,l,mid);
	build(k*2+1,mid+1,r);
	ret(k);
}
void update(ll k){
	ll b=R[k*2]-L[k*2]+1,c=R[k*2+1]-L[k*2+1]+1;
	if(lazy_paint[k]!=-1){
		lazy_paint[k*2]=lazy_paint[k];
		lazy_paint[k*2+1]=lazy_paint[k];

		sum[k*2]=b*lazy_paint[k];
		sum[k*2+1]=c*lazy_paint[k];

		len[k*2][1]={sum[k*2],sum[k*2],sum[k*2]};
		len[k*2+1][1]={sum[k*2+1],sum[k*2+1],sum[k*2+1]};

		len[k*2][0]={b-sum[k*2],b-sum[k*2],b-sum[k*2]};
		len[k*2+1][0]={c-sum[k*2+1],c-sum[k*2+1],c-sum[k*2+1]};

		lazy_paint[k]=-1;
	}
	if(lazy_rev[k]!=0){
		lazy_rev[k*2]^=lazy_rev[k];
		lazy_rev[k*2+1]^=lazy_rev[k];

		sum[k*2]=b-sum[k*2];
		sum[k*2+1]=c-sum[k*2+1];

		swap(len[k*2][1],len[k*2][0]);
		swap(len[k*2+1][1],len[k*2+1][0]);

		lazy_rev[k]=0;
	}
}
void paint(ll k,ll l,ll r,ll v){
	if(L[k]>=l&&R[k]<=r){
		ll b=R[k]-L[k]+1;
		lazy_paint[k]=v;
		lazy_rev[k]=0;
		sum[k]=b*v;
		len[k][1]={sum[k],sum[k],sum[k]};
		len[k][0]={b-sum[k],b-sum[k],b-sum[k]};
		return;
	}
	update(k);
	ll mid=(L[k]+R[k])/2;
	if(l<=mid)paint(k*2,l,r,v);
	if(r>=mid+1)paint(k*2+1,l,r,v);
	ret(k);
}
void rev(ll k,ll l,ll r){
	if(L[k]>=l&&R[k]<=r){
		lazy_rev[k]^=1;
		sum[k]=(R[k]-L[k]+1)-sum[k];
		swap(len[k][1],len[k][0]);
		return;
	}
	update(k);
	ll mid=(L[k]+R[k])/2;
	if(l<=mid)rev(k*2,l,r);
	if(r>=mid+1)rev(k*2+1,l,r);
	ret(k);
}
ll cha(ll k,ll l,ll r){
	if(L[k]>=l&&R[k]<=r){
		return sum[k];
	}
	update(k);
	ll mid=(L[k]+R[k])/2,res=0;
	if(l<=mid)res+=cha(k*2,l,r);
	if(r>=mid+1)res+=cha(k*2+1,l,r);
	return res;
}
A cha2(ll k,ll l,ll r){
	if(L[k]>=l&&R[k]<=r){
		return len[k][1];
	}
	update(k);
	ll mid=(L[k]+R[k])/2;
	A b={0,0,0},c={0,0,0};
	if(l<=mid)b=cha2(k*2,l,r);
	if(r>=mid+1)c=cha2(k*2+1,l,r);
	A res={b.l,max(b.r+c.l,max(b.mid,c.mid)),c.r};
	if(b.l==R[k*2]-L[k*2]+1)res.l+=c.l;
	if(c.r==R[k*2+1]-L[k*2+1]+1)res.r+=b.r;
	res.mid=max(res.mid,res.l);
	res.mid=max(res.mid,res.r);
	if(l>L[k])res.l=0;
	if(r<R[k])res.r=0;
	return res;
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	build(1,1,n);
	for(int i=1;i<=m;i++){
		ll k,l,r;
		cin>>k>>l>>r;
		l++;r++;
		if(k==0)paint(1,l,r,0);
		else if(k==1)paint(1,l,r,1);
		else if(k==2)rev(1,l,r);
		else if(k==3)cout<<cha(1,l,r)<<'\n';
		else{
			A k=cha2(1,l,r);
			cout<<max(k.l,max(k.mid,k.r))<<'\n';
		}
	}
	return 0;
}

