const int N=3e5+5;
ll n,a[N],b[N],len,lz[N];

int P(int p){
	return (p+len-1)/len;
}
int L(int p){
	return (p-1)*len+1;
}
int R(int p){
	return p*len;
}

void st(int p){
	for(int i=L(p);i<=R(p);i++)b[i]=a[i];
	sort(b+L(p),b+R(p)+1);
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n;
	len=sqrt(n);
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	for(int i=n+1;i<=R(P(n));i++)a[i]=0x7ffffffffffffff;
	for(int i=1;i<=P(n);i++)st(i);
	for(int i=1;i<=n;i++){
		ll opt,l,r,c;
		cin>>opt>>l>>r>>c;

		int pl=P(l),pr=P(r); 

		int jll=((l-1)%len==0?1:0),
			jlr=(    r%len==0?1:0);//是否是块左/右端点 

		int jl;//是否有整块 
		if(jll&&jlr)jl=1;
		else if(jll||jlr)jl=(pl!=pr?1:0);
		else{jl=((pr-pl)>1?1:0);}

		int x=pl,y=pr;//左右整块
		if(jl){
			if(!jll)x++;
			if(!jlr)y--;
		}

		if(opt==0){
			if(jl==0){
				for(int p=l;p<=r;p++)a[p]+=c;
				st(pl),st(pr);
			}
			else{
				for(int p=l;p<=(x-1)*len;p++)a[p]+=c;
				if(jll==0)st(pl);
				for(int p=x;p<=y;p++)lz[p]+=c;
				for(int p=x*len+1;p<=r;p++)a[p]+=c;
				if(jlr==0)st(pr);
			}
		}
		else{
			c*=c;
			int ans=0;
			if(jl==0){
				if(pl==pr)for(int p=l;p<=r;p++)ans+=((c-lz[pl])>a[p]?1:0);
				else{
					for(int p=l;p<=x*len;p++)      ans+=((c-lz[pl])>a[p]?1:0);
					for(int p=(y-1)*len+1;p<=r;p++)ans+=((c-lz[pr])>a[p]?1:0);
				}
			}
			else{
				for(int p=l ;p<=(x-1)*len;p++)ans+=((c-lz[pl])>a[p]?1:0);
				for(int p=x;p<=y;p++)        ans+=lower_bound(b+L(p),b+R(p)+1,c-lz[p])-b-L(p);
				for(int p=y*len+1;p<=r;p++)   ans+=((c-lz[pr])>a[p]?1:0);
			}
			cout<<ans<<'\n';
		}
	}
	return 0;
}

#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=1e5+5;
ll t,n,a[N],f[N],g[N],q;
ll he,hef,heg,hemx;
struct A{
	ll sum,mn,mx;
};
A tf[4*N],tg[4*N],tmx[4*N];
ll L[4*N],R[4*N],lazf[4*N],lazg[4*N],lazmx[4*N];

A (*tr)[4*N];
ll (*lz)[4*N];

void up(int k){
	(*tr)[k].sum=(*tr)[k*2].sum+(*tr)[k*2+1].sum;
	(*tr)[k].mn=min((*tr)[k*2].mn,(*tr)[k*2+1].mn);
	(*tr)[k].mx=max((*tr)[k*2].mx,(*tr)[k*2+1].mx);
}
void build(int k,int l,int r){
	L[k]=l;R[k]=r;
	lazf[k]=lazg[k]=lazmx[k]=0;
	if(l==r){
		tf[k]={f[l],f[l],f[l]};
		tg[k]={g[l],g[l],g[l]};
		if(f[l]>g[l])tmx[k]={f[l],f[l],f[l]};
		else tmx[k]={g[l],g[l],g[l]};
		hemx+=tmx[k].sum;
		return;
	}
	int mid=(l+r)/2;
	build(k*2,l,mid);
	build(k*2+1,mid+1,r);
	tr=&tf;up(k);
	tr=&tg;up(k);
	tr=&tmx;up(k);
}
void pnt(int k,int v){
	(*lz)[k]=v;
	(*tr)[k].sum=v*(R[k]-L[k]+1);
	(*tr)[k].mn=v;
	(*tr)[k].mx=v;
}
void update(int k){
	if((*lz)[k]==0)return;
	pnt(k*2,(*lz)[k]);
	pnt(k*2+1,(*lz)[k]);
	(*lz)[k]=0;
}
void addf(int k,int p,int v){
	if(tf[k].mn>=v)return;
	if(p<=L[k]){
		if(tf[k].mx<=v){
			hef+=v*(R[k]-L[k]+1)-tf[k].sum;
			pnt(k,v);
			return;
		}
		update(k);
		addf(k*2,p,v);
		if(tf[k*2+1].mn<v)addf(k*2+1,p,v);
		up(k);
	}
	else{
		update(k);
		int mid=(L[k]+R[k])/2;
		if(p<=mid)addf(k*2,p,v);
		addf(k*2+1,p,v);
		up(k);
	}
}
void addg(int k,int p,int v){
	if(tg[k].mn>=v)return;
	if(p>=R[k]){
		if(tg[k].mx<=v){
			heg+=v*(R[k]-L[k]+1)-tg[k].sum;
			pnt(k,v);
			return;
		}
		update(k);
		addg(k*2+1,p,v);
		if(tg[k*2].mn<v)addg(k*2,p,v);
		up(k);
	}
	else{
		update(k);
		int mid=(L[k]+R[k])/2;
		if(p>=mid+1)addg(k*2+1,p,v);
		addg(k*2,p,v);
		up(k);
	}
}
void addmx(int k,int v){
	if(tmx[k].mn>=v)return;
	if(tmx[k].mx<=v){
		hemx+=v*(R[k]-L[k]+1)-tmx[k].sum;
		pnt(k,v);
		return;
	}
	update(k);
	if(tmx[k*2].mn<v)addmx(k*2,v);
	if(tmx[k*2+1].mn<v)addmx(k*2+1,v);
	up(k);
}
void prt(int k){
	cout<<k<<"{sum:"<<(*tr)[k].sum<<" mn:"<<(*tr)[k].mn<<" mx:"<<(*tr)[k].mx<<"}\n";
	if(L[k]==R[k]){

		return;
	}
	prt(k*2);
	prt(k*2+1);
}
int main(){
	ios::sync_with_stdio(false);
	cin>>t;
	while(t--){
		cin>>n;
		he=hef=heg=hemx=0;g[n+1]=0;
		for(int i=1;i<=n;i++){
			cin>>a[i];
			f[i]=max(f[i-1],a[i]);
			he+=a[i];
			hef+=f[i];
		}
		for(int i=n;i>=1;i--){
			g[i]=max(g[i+1],a[i]);
			heg+=g[i];
		}
		build(1,1,n);
		//cout<<hef<<' '<<heg<<' '<<hemx<<' '<<he<<'\n';////////
		//tr=&tg;prt(1);//////////////////////
		cin>>q;
		for(int i=1;i<=q;i++){
			int x,v;
			cin>>x>>v;
			he+=v;
			tr=&tf;lz=&lazf;
			addf(1,x,a[x]+v);
			tr=&tg;lz=&lazg;
			addg(1,x,a[x]+v);
			tr=&tmx;lz=&lazmx;
			addmx(1,a[x]+v);
			a[x]+=v;
			//tr=&tg;prt(1);//////////////////////
			//cout<<hef<<' '<<heg<<' '<<hemx<<' '<<he<<'\n';////////heg
			cout<<hef+heg-hemx-he<<'\n';
		}
	}
	return 0;
}
