#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=1e6+5;
int n,x,y,z,a[N],b[N],c[N];
ll f[N];
ll sum[N*4],L[N*4],R[N*4];
void build(int k,int l,int r){
	L[k]=l;R[k]=r;
	if(l==r){
		return;
	}
	int mid=(l+r)/2;
	build(k*2,l,mid);
	build(k*2+1,mid+1,r);
}
void add(int k,int p){
	sum[k]++;
	if(L[k]==R[k]){
		return;
	}
	int mid=(L[k]+R[k])/2;
	if(p<=mid)add(k*2,p);
	else add(k*2+1,p);
}
int cha(int k,int l,int r){
	if(L[k]>=l&&R[k]<=r){
		return sum[k];
	}
	int mid=(L[k]+R[k])/2,res=0;
	if(l<=mid)res+=cha(k*2,l,r);
	if(r>=mid+1)res+=cha(k*2+1,l,r);
	return res;
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>x>>y>>z;
	build(1,1,n);
	for(int i=1;i<=n;i++){
		cin>>a[i];
		c[a[i]]=i;
	}
	for(int i=1;i<=n;i++){
		cin>>b[i];
	}
	for(int i=1;i<=n;i++){
		int p1=c[i-1],p2=c[i];
		if(i==1)p1=1;
		//cout<<"p"<<p1<<' '<<p2<<'\n';//
		int ans=N;
		if(p1<p2){
			int cnt1=cha(1,p1,p2),cnt2=cha(1,1,p1),cnt3=cha(1,p2,n);
			ans=min(x*(p2-p1-cnt1),min(z+y*(p2-p1-cnt1),y*(n-p2+p1-cnt2-cnt3)));
			//cout<<"\na"<<cnt1<<' '<<cnt2<<' '<<cnt3<<' '<<ans<<'\n';//
			//cout<<"b"<<x*(p2-p1-cnt1)<<' '<<z+y*(p2-p1-cnt1)<<' '<<y*(n-p2+p1-cnt2-cnt3)<<'\n';//
		}
		else{
			int cnt1=cha(1,p2,p1),cnt2=cha(1,1,p2),cnt3=cha(1,p1,n);
			ans=min(x*(p1-p2-cnt1),min(z+y*(p1-p2-cnt1),y*(n-p1+p2-cnt2-cnt3)));
		}
		f[i]=f[i-1]+ans;
		add(1,p2);
		//cout<<f[i]<<' ';//
	}
	cout<<f[n];
	return 0;
}

