double energy(P k){
	double res=0;
	for(int i=1;i<=n;i++){
		res+=sqrt((p[i].x-k.x)*(p[i].x-k.x)+(p[i].y-k.y)*(p[i].y-k.y));
	}
	return res;
}
P move(P k,double T){
	double dx=2*rand()-RAND_MAX,dy=2*rand()-RAND_MAX;
	return {k.x+dx*T,k.y+dy*T};
}
void SA(){
	double T=200;
	while(T>=eps){
		P p_cur=move(p_last,T);
		double a_cur=energy(p_cur);
		if(a_cur<a_last){
			a_last=a_cur;
			p_last=p_cur;
		}
		else if(exp((a_last-a_cur)/T)*RAND_MAX>rand()){
			a_last=a_cur;
			p_last=p_cur;
		}
		if(a_cur<a_best){
			a_best=a_cur;
			p_best=p_cur;
		}
		T*=delT;
	}
}
