#include <bits/stdc++.h>
using namespace std;
long long n,m,cnt=99999999,cnt2,minn=99999999;
void DFS(int floor,int val,int high,int r){
	if(floor==m){
		if(!val){
			cnt=min(cnt,cnt2);
		}
		return;
	}
	if(val==0)return;
	if(cnt2>=cnt)return;
	if(cnt2>=minn)return;
	for(int i=m-floor;i<high;i++){
		for(int l=m-floor;l<r;l++){
			if(val-i*i*l>=0){
				cnt2+=2*i*l;
				DFS(floor+1,val-i*i*l,i,l);
				cnt2-=2*i*l;
			}
			else break;
		}
	}
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>m;
	for(int i=m;i*i<=n/m;i++){
		for(int l=m;l<=n/(i*i);l++){
			if(n-i*i*l>=0){
				cnt2+=2*i*l;
				cnt=99999999;
				DFS(1,n-i*i*l,i,l);
				minn=min(minn,cnt+i*i);
				cnt2-=2*i*l;
			}
			else break;
		}
	}
	cout<<minn;
	return 0;
}

