vector<ll>vec[500002],vec2[500002],sta[500002];
void DFS(ll K,ll f,ll id){
	sta2[p2++]=K;
	for(int i=0;i<vec[K].size();i++){
		if(!vis[vec[K][i]]){
			low[vec[K][i]]=stp[vec[K][i]]=stp[K]+1;
			vis[vec[K][i]]=1;
			DFS(vec[K][i],K,vec2[K][i]);
			low[K]=min(low[K],low[vec[K][i]]);
		}
		else{
			if((vec[K][i]!=f||(vec2[K][i]!=id))&&stp[vec[K][i]]){
				low[K]=min(low[K],stp[vec[K][i]]);
			}
		}
	}
	if(low[K]==stp[K]){
		while(p2>1){
			sta[p].push_back(sta2[p2-1]);
			p2--;
			if(sta2[p2]==K)break;
		}
		p++;
	}
}
