    		vec2[v].push_back(i);
		}
	}
	for(int i=1;i<=n;i++){
		if(!stp[i]){
			vis[i]=1;
			low[i]=stp[i]=1;
			DFS(i,-1,-1);
		}
	}
	cout<<p-1<<'\n';
	for(int i=1;i<p;i++){
		if(ma<sta[i].size()){
			ma=sta[i].size();
			k=i;
		}
		//cout<<'\n'<<sta[i].size()<<' ';
	}
	for(int l=sta[k].size()-1;l>=0;l--){
		cout<<sta[k][l]<<' ';
	}
    return 0;
}

