void dfs(int k,i128 l,i128 r){
	for(int i=0;i<vec[k].size();i++){
		int to=vec[k][i].u;
		i128* L=&vec[k][i].l;i128* R=&vec[k][i].r;
		sum[to]+=sum[k];
		*L-=sum[k];
		*R-=sum[k];
