#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=6e5+5;
int n,a[N],st[N][30],mn2[N],mx2[N],mn3[N],mx3[N];//第一个<=2的gcd的位置 第一个<2的gcd的位置 
int erfen(int v,int p,int l,int r){//第一个<=v的下标
    int mid;
    while(l<r-1){
        mid=(l+r)/2;
        int i=__lg(mid-p+1);
        if(__gcd(st[p][i],st[mid-(1<<i)+1][i])>v)l=mid;
        else r=mid;
    }
    return r;
}
ll cal(int i,int k,int* mn,int* mx){
    int p1,p2,l,r;
    if(mn[i]==0x7fffffff||mn[i]==mx[i])return 0;
    if(mn[i]<=1)p1=i+mn[i];
    else{
        l=i+(1<<(mn[i]-1))-1,r=i+(1<<mn[i])-1;
        p1=erfen(k,i,l,r);
    }
    if(mx[i]==1){
        if(k==3&&mn[i]==0)return 1;
        return 0;
    }

    if(mx[i]==0x7fffffff)l=p1,r=n+1;
    else l=i+(1<<(mx[i]-1))-1,r=i+(1<<mx[i])-1;
    p2=erfen(k-1,i,l,r)-1;

    int len1=p1-i+1,len2=p2-i+1;
    //cout<<"p "<<p1<<' '<<p2<<'\n';//
    if(len1%2==!(k%2))len1++,p1++;
    if(len2%2==!(k%2))len2--,p2--;
    //cout<<"p "<<p1<<' '<<p2<<'\n';//
    if(len1<=len2)return (len2+len1)*((p2-p1)/2+1)/2;
    return 0;
}
int main() {
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i];
        st[i][0]=a[i];
        mn2[i]=mn3[i]=mx2[i]=mx3[i]=0x7fffffff;
        if(a[i]==2)mn2[i]=0;
        if(a[i]==3)mn3[i]=0;
    }
    for(int i=1;i<=__lg(n);i++){
        for(int l=1;l+(1<<i)-1<=n;l++){
            st[l][i]=__gcd(st[l][i-1],st[l+(1<<(i-1))][i-1]);
            if(st[l][i]<=2){
                mn2[l]=min(mn2[l],i);
                if(st[l][i]<2)mx2[l]=min(mx2[l],i);
            }
            if(st[l][i]<=3){
                mn3[l]=min(mn3[l],i);
                if(st[l][i]<3)mx3[l]=min(mx3[l],i);
            }
        }
    }
    ll ans=0;
    for(int i=1;i<=n;i++){
        //cout<<"i="<<i<<'\n';//
        int p1,p2,l,r;
        if(a[i]%2==0)ans+=cal(i,2,mn2,mx2);
        if(a[i]%3==0)ans+=cal(i,3,mn3,mx3);
        //cout<<"ans"<<ans<<"\n";//
    }
    cout<<ans;
}/*
